class Solution:
    def numWays(self, steps: int, arrLen: int) -> int:
        MOD = 10**9 + 7
        if arrLen == 1:
            return 1
        max_pos = min(arrLen - 1, steps)
        prev = [0] * (max_pos + 1)
        prev[0] = 1
        for _ in range(steps):
            curr = [0] * (max_pos + 1)
            for j in range(max_pos + 1):
                if j - 1 >= 0:
                    curr[j] += prev[j - 1]
                curr[j] += prev[j]
                if j + 1 <= max_pos:
                    curr[j] += prev[j + 1]
                curr[j] %= MOD
            prev = curr.copy()
        return prev[0] % MOD

